// Test to understand the range computation
#include <iostream>
#include <cstdint>

int main() {
    // Range [0, 6) means values 0, 1, 2, 3, 4, 5
    // Cases: {0, 4, 5} go to one destination
    // Default: {1, 2, 3} goes to another

    // Complement of {0, 4, 5} in [0, 6) is {1, 2, 3}
    // This is contiguous! Start = 1, Size = 3

    // The check should be: (arg - 1) < 3
    // If true, go to default (else)
    // If false, go to cases (if)

    std::cout << "Testing range check:" << std::endl;
    for (int arg = 0; arg < 6; arg++) {
        int add = arg - 1;  // add i8 %arg, -1
        bool cmp = (add < 3) && (add >= 0);  // icmp ult i8 %add, 3
        // Actually, ult means unsigned less than, so we need to check if add < 3 (unsigned)
        // For i8, values are 0-255
        // arg=0: add=-1 (255 unsigned), 255 < 3? false
        // arg=1: add=0, 0 < 3? true
        // arg=2: add=1, 1 < 3? true
        // arg=3: add=2, 2 < 3? true
        // arg=4: add=3, 3 < 3? false
        // arg=5: add=4, 4 < 3? false

        uint8_t add_u8 = static_cast<uint8_t>(arg - 1);
        bool ult = add_u8 < 3;

        std::cout << "arg=" << arg << ": add=" << (int)add_u8 << ", ult<3=" << ult << std::endl;
    }

    return 0;
}
EOF
